import { Route } from 'react-router-dom';
import './App.css';
import Routes, { routes } from './routes/routes'

function App() {
  return (
  <div className='App'>
      <Routes>
        {routes.map((route, index) =>(
          <Route
          key={index}
          path={route.path}
          element={route.element}
          />
        ))}
    </Routes>

  </div>
  );
}

export default App;
